import{_ as e,a}from"./chunks/webdav在win显示效果.BVTuSvY9.js";import{_ as i,o as l,c as d,a2 as r}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"WebDAV 設定與存取（Beta）","description":"","frontmatter":{},"headers":[],"relativePath":"zh-TW/Safety/webdav-site-access.md","filePath":"zh-TW/Safety/webdav-site-access.md","lastUpdated":1781962217000}'),s={name:"zh-TW/Safety/webdav-site-access.md"};function o(h,t,n,b,p,c){return l(),d("div",null,[...t[0]||(t[0]=[r('<h1 id="webdav-設定與存取-beta" tabindex="-1">WebDAV 設定與存取（Beta） <a class="header-anchor" href="#webdav-設定與存取-beta" aria-label="Permalink to &quot;WebDAV 設定與存取（Beta）&quot;">​</a></h1><p>安全設定裡的 WebDAV 是把 ImgBed 站台開成一個 WebDAV 存取入口。</p><p>設定後，你可以在 Windows、macOS、手機檔案管理器或支援 WebDAV 的用戶端裡，把 ImgBed 當成遠端資料夾使用，直接瀏覽、上傳、刪除和管理檔案。</p><p>這裡的 WebDAV 是「站台存取入口」，不是上傳設定裡的「WebDAV 儲存渠道」。上傳渠道的 WebDAV 是把第三方 WebDAV 服務當作儲存位置；安全設定裡的 WebDAV 是讓你的 ImgBed 站台對外提供 WebDAV 存取。</p><h2 id="功能入口" tabindex="-1">功能入口 <a class="header-anchor" href="#功能入口" aria-label="Permalink to &quot;功能入口&quot;">​</a></h2><p>進入後台後打開：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>系統設定 -&gt; 安全設定 -&gt; WebDAV</span></span></code></pre></div><p>頁面裡可以設定：</p><ul><li>啟用</li><li>使用者名稱</li><li>密碼</li><li>圖片載入模式</li><li>預設渠道</li></ul><h2 id="這個功能有什麼用" tabindex="-1">這個功能有什麼用 <a class="header-anchor" href="#這個功能有什麼用" aria-label="Permalink to &quot;這個功能有什麼用&quot;">​</a></h2><p>開啟 WebDAV 後，系統會提供固定存取網址：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://你的網域/dav</span></span></code></pre></div><p>適合這些情境：</p><ul><li>在電腦檔案總管裡直接查看 ImgBed 檔案。</li><li>把圖片拖進 WebDAV 目錄完成上傳。</li><li>像整理本機資料夾一樣整理 ImgBed 目錄。</li><li>使用支援 WebDAV 的軟體同步或管理圖片。</li><li>不打開後台，也能透過檔案管理器存取圖床內容。</li></ul><h2 id="設定項目" tabindex="-1">設定項目 <a class="header-anchor" href="#設定項目" aria-label="Permalink to &quot;設定項目&quot;">​</a></h2><h3 id="啟用" tabindex="-1">啟用 <a class="header-anchor" href="#啟用" aria-label="Permalink to &quot;啟用&quot;">​</a></h3><p>開啟後，WebDAV 入口才會生效。</p><p>關閉後，用戶端無法透過 WebDAV 連接 ImgBed。</p><h3 id="使用者名稱和密碼" tabindex="-1">使用者名稱和密碼 <a class="header-anchor" href="#使用者名稱和密碼" aria-label="Permalink to &quot;使用者名稱和密碼&quot;">​</a></h3><p>這是 WebDAV 用戶端連線時使用的帳號。</p><p>建議單獨設定一組 WebDAV 專用帳密，不要和後台管理密碼、上傳密碼共用。</p><p>如果沒有填使用者名稱或密碼，WebDAV 用戶端無法正常連線。</p><h3 id="圖片載入模式" tabindex="-1">圖片載入模式 <a class="header-anchor" href="#圖片載入模式" aria-label="Permalink to &quot;圖片載入模式&quot;">​</a></h3><p>圖片載入模式決定 WebDAV 用戶端讀取圖片時優先使用哪種圖片位址。</p><table tabindex="0"><thead><tr><th>模式</th><th>說明</th></tr></thead><tbody><tr><td>智慧載入</td><td>系統依情境自動選擇，日常使用建議選這個</td></tr><tr><td>原圖</td><td>優先讀取原始圖片</td></tr><tr><td>縮圖</td><td>優先讀取縮圖，適合快速預覽</td></tr></tbody></table><p>不確定時保持「智慧載入」即可。</p><h3 id="預設渠道" tabindex="-1">預設渠道 <a class="header-anchor" href="#預設渠道" aria-label="Permalink to &quot;預設渠道&quot;">​</a></h3><p>預設渠道用於 WebDAV 上傳檔案。</p><p>當你從 Windows 或其他 WebDAV 用戶端把檔案複製到 ImgBed 目錄時，系統會把檔案上傳到這裡選的預設渠道。</p><p>如果沒有選預設渠道，WebDAV 可以瀏覽，但上傳可能會失敗。</p><h2 id="在-windows-11-中存取" tabindex="-1">在 Windows 11 中存取 <a class="header-anchor" href="#在-windows-11-中存取" aria-label="Permalink to &quot;在 Windows 11 中存取&quot;">​</a></h2><p>Windows 11 可以把 WebDAV 新增成網路位置。</p><ol><li>打開「本機」。</li><li>選「新增網路位置」。</li><li>位址填 <code>https://你的網域/dav</code>。</li><li>依提示輸入 WebDAV 使用者名稱和密碼。</li><li>完成後，就可以在檔案總管裡打開 WebDAV 目錄。</li></ol><p><img src="'+e+'" alt="Windows 11 新增 WebDAV" loading="lazy"></p><p>新增完成後，Windows 檔案總管裡會顯示 WebDAV 目錄。你可以像一般資料夾一樣打開、複製和管理檔案。</p><p><img src="'+a+'" alt="WebDAV 在 Windows 中的效果" loading="lazy"></p><h2 id="可以做哪些操作" tabindex="-1">可以做哪些操作 <a class="header-anchor" href="#可以做哪些操作" aria-label="Permalink to &quot;可以做哪些操作&quot;">​</a></h2><p>WebDAV 連線成功後，通常可以：</p><ul><li>查看檔案和資料夾。</li><li>上傳檔案。</li><li>新增資料夾。</li><li>重新命名檔案或資料夾。</li><li>移動檔案。</li><li>刪除檔案。</li></ul><p>WebDAV 比較適合日常存取和少量檔案管理。大量移動、批次刪除或複雜整理，建議在後台管理頁操作。</p><h2 id="登入裝置管理" tabindex="-1">登入裝置管理 <a class="header-anchor" href="#登入裝置管理" aria-label="Permalink to &quot;登入裝置管理&quot;">​</a></h2><p>WebDAV 連線成功後，也會出現在「登入裝置管理」的 WebDAV 分頁。</p><p>你可以在那裡查看 WebDAV 用戶端登入裝置，必要時讓舊裝置登出。</p><p>如果修改 WebDAV 使用者名稱或密碼，舊用戶端需要重新登入。</p><h2 id="常見問題" tabindex="-1">常見問題 <a class="header-anchor" href="#常見問題" aria-label="Permalink to &quot;常見問題&quot;">​</a></h2><h3 id="windows-一直要求輸入帳號密碼" tabindex="-1">Windows 一直要求輸入帳號密碼 <a class="header-anchor" href="#windows-一直要求輸入帳號密碼" aria-label="Permalink to &quot;Windows 一直要求輸入帳號密碼&quot;">​</a></h3><p>可以依序檢查：</p><ul><li>位址是否填 <code>https://你的網域/dav</code>。</li><li>使用者名稱和密碼是否和後台 WebDAV 設定一致。</li><li>WebDAV 是否已啟用。</li><li>站台是否能透過 HTTPS 正常存取。</li></ul><h3 id="可以瀏覽-但上傳失敗" tabindex="-1">可以瀏覽，但上傳失敗 <a class="header-anchor" href="#可以瀏覽-但上傳失敗" aria-label="Permalink to &quot;可以瀏覽，但上傳失敗&quot;">​</a></h3><p>通常需要檢查「預設渠道」。</p><p>WebDAV 上傳需要一個預設上傳渠道。如果預設渠道沒設定、被停用或設定不可用，上傳可能會失敗。</p><h3 id="存取速度不穩" tabindex="-1">存取速度不穩 <a class="header-anchor" href="#存取速度不穩" aria-label="Permalink to &quot;存取速度不穩&quot;">​</a></h3><p>WebDAV 體驗會受用戶端、網路、圖片數量和預設上傳渠道影響。</p><p>如果目錄檔案非常多，建議先分資料夾整理，不要把太多檔案放在同一個目錄。</p><h2 id="安全建議" tabindex="-1">安全建議 <a class="header-anchor" href="#安全建議" aria-label="Permalink to &quot;安全建議&quot;">​</a></h2><ul><li>使用 HTTPS 存取 WebDAV。</li><li>設定強密碼。</li><li>不要把 WebDAV 密碼給不信任的人。</li><li>不使用時可以關閉 WebDAV。</li><li>定期在登入裝置管理裡清理不用的 WebDAV 裝置。</li></ul><h2 id="webdav-上傳檔案大小" tabindex="-1">WebDAV 上傳檔案大小 <a class="header-anchor" href="#webdav-上傳檔案大小" aria-label="Permalink to &quot;WebDAV 上傳檔案大小&quot;">​</a></h2><p>WebDAV 用戶端上傳不支援網頁端的大檔案分段流程。超過下表建議大小時，請改用網頁上傳。</p><table tabindex="0"><thead><tr><th>預設上傳渠道</th><th style="text-align:right;">WebDAV 單檔建議上限</th></tr></thead><tbody><tr><td>Telegram</td><td style="text-align:right;">20 MB</td></tr><tr><td>Discord</td><td style="text-align:right;">10 MB</td></tr><tr><td>Cloudflare R2</td><td style="text-align:right;">30 MB</td></tr><tr><td>S3</td><td style="text-align:right;">30 MB</td></tr><tr><td>GitHub Releases</td><td style="text-align:right;">64 MB</td></tr><tr><td>GitLab Packages</td><td style="text-align:right;">64 MB</td></tr><tr><td>Hugging Face</td><td style="text-align:right;">20 MB</td></tr><tr><td>OneDrive</td><td style="text-align:right;">30 MB</td></tr><tr><td>Google Drive</td><td style="text-align:right;">30 MB</td></tr><tr><td>Dropbox</td><td style="text-align:right;">30 MB</td></tr><tr><td>Yandex Disk</td><td style="text-align:right;">30 MB</td></tr><tr><td>pCloud</td><td style="text-align:right;">30 MB</td></tr><tr><td>WebDAV</td><td style="text-align:right;">64 MB</td></tr></tbody></table>',59)])])}const D=i(s,[["render",o]]);export{g as __pageData,D as default};
